def get_db_connection():
    """Zentrale DB-Verbindung"""
    if not DB_PATH.exists():
        return None
    return sqlite3.connect(DB_PATH)


def load_json_safe(path: Path) -> dict | list | None:
    """Lädt JSON sicher, gibt None bei Fehler zurück"""
    try:
        if path.exists():
            with open(path) as f:
                return json.load(f)
    except Exception as e:
        print(f"[WARN] Konnte {path.name} nicht laden: {e}")
    return None


